// Este array contendrá cada línea del historial formateada.
const chatHistory = [];

// Iteramos sobre cada uno de los 10 items que llegan al nodo.
for (const item of items) {
  try {
    // El campo 'message' es un texto que parece JSON (stringified JSON).
    // Primero, lo convertimos a un objeto JSON real.
    const messageObject = JSON.parse(item.json.message);

    const type = messageObject.type; // Será 'human' o 'ai'.
    const content = messageObject.content;
    let finalContent = '';

    // El contenido de los mensajes humanos a veces es un array dentro de un string.
    // Intentamos procesarlo. Si falla, lo tratamos como texto normal.
    try {
      const parsedContent = JSON.parse(content);
      if (Array.isArray(parsedContent)) {
        // Si es un array, unimos sus partes.
        finalContent = parsedContent.join(' ');
      } else {
        finalContent = content;
      }
    } catch (e) {
      // Si no se pudo parsear, es porque ya era un string simple (como los de la IA).
      finalContent = content;
    }

    // Asignamos un rol legible para el LLM.
    const role = type === 'human' ? 'Humano' : 'MIA';

    // Limpiamos el texto de saltos de línea excesivos y espacios extra.
    const cleanedContent = finalContent.replace(/\\n/g, ' ').replace(/\s+/g, ' ').trim();

    // Añadimos la línea formateada a nuestro historial.
    chatHistory.push(`${role}: ${cleanedContent}`);

  } catch (error) {
    // Si algún mensaje no es un JSON válido, lo ignoramos para no detener el flujo.
    console.log(`Error procesando un mensaje: ${error.message}`);
  }
}

// Unimos todas las líneas del historial en un solo bloque de texto,
// separado por dos saltos de línea para mayor claridad.
const fullHistoryText = chatHistory.join('\n\n');

// El nodo Code debe devolver un array. Devolvemos un array con UN SOLO item,
// que contiene nuestro historial completo.
return [{
  json: {
    historial_completo: fullHistoryText
  }
}];

